import { NESTED_VIEW_CLASSNAME } from '../../../../view/view-constants';
import { PATH_ELEMENT } from '../../../../core/element-constants';
import { ORDINAL_DATATYPE } from '../../../../core/datatype-constants';
import { getSvgTransform } from '../../../../utils/svg-transforms';
import { getSVGTooltipPosition } from '../highlight-tooltip';

export function ShowTooltip(mouse, data) {
    let manager = this,
        { options } = manager,
        { tooltip, format, config, highlightElement, dataType } = options,
        { ranges: userRanges } = config,
        { point } = data,
        d = dataType === ORDINAL_DATATYPE ? userRanges[point][0] : userRanges && userRanges.length ? userRanges[point] : point[0];

    // Position
    let ele = highlightElement.selectAll(`g.${NESTED_VIEW_CLASSNAME}`).selectAll(PATH_ELEMENT),
        position = getSVGTooltipPosition(ele, tooltip.config, undefined, getSvgTransform(ele).translate); // getSVGTooltipPosition should be called before tooltip.show

    // Content
    tooltip.show(format(d));

    tooltip.positionTooltip(position);
}
